const inputs = $input.all();

let results = [];

for (const feed of inputs) {
  const xml = feed.json.data;

  // ✅ SAFETY GUARD (correct place)
  if (!xml || typeof xml !== 'string') {
    continue;
  }

  // First <item> only
  const itemMatch = xml.match(/<item>([\s\S]*?)<\/item>/);
  if (!itemMatch) continue;

  const item = itemMatch[1];

  const title =
    item.match(/<title><!\[CDATA\[(.*?)\]\]><\/title>/)?.[1] ||
    item.match(/<title>(.*?)<\/title>/)?.[1] ||
    'No title';

  let link =
    item.match(/<link>(.*?)<\/link>/)?.[1] ||
    item.match(/<guid>(.*?)<\/guid>/)?.[1] ||
    '';

  link = link.trim();

  // ❗ invalid / relative links skip
  if (!link.startsWith('http')) {
    continue;
  }

  const description =
    item.match(/<description><!\[CDATA\[(.*?)\]\]><\/description>/)?.[1] ||
    item.match(/<description>(.*?)<\/description>/)?.[1] ||
    '';

  results.push({
    title: title.trim(),
    link,
    description: description.trim().replace(/<[^>]+>/g, '')
  });
}

return results.map(r => ({ json: r }));

const items = $input.all();

function detectCategory(link, title) {
  const t = title.toLowerCase();

  // CRYPTO
  if (link.includes('coindesk.com') || link.includes('cointelegraph.com')) {
    return 'crypto';
  }

  // INVESTING.COM → keyword based
  if (link.includes('investing.com')) {
    if (t.includes('gold') || t.includes('bullion') || t.includes('precious')) {
      return 'gold';
    }

    return 'finance'; // oil, opec, markets, economy, etc.
  }

  return 'other';
}

function buildMessage(title, category) {
  if (category === 'crypto') {
    return `📰 <b>Crypto News</b> ₿

${title}

⏱ Just now

#Crypto #Bitcoin #Blockchain #CryptoNews`;
  }

  if (category === 'gold') {
    return `📰 <b>Gold Market Update</b> 🟡

${title}

⏱ Just now

#Gold #PreciousMetals #Commodities`;
  }

  if (category === 'finance') {
    return `📰 <b>Market News</b> 📊

${title}

⏱ Just now

#Markets #Finance #Economy #GlobalNews`;
  }

  return null;
}

let output = [];

for (const item of items) {
  const { title, link } = item.json;

  const category = detectCategory(link, title);
  const message = buildMessage(title, category);

  if (!message) continue;

  output.push({
    json: {
      category,
      title,
      link,
      message
    }
  });
}

return output;

const items = $input.all();
const staticData = $getWorkflowStaticData('global');

// Create DB if not exists
if (!staticData.db) {
  staticData.db = {
    posted: {},
    lock: false
  };
}

// 🔒 HARD LOCK — agar already post select ho chuki hai
if (staticData.db.lock === true) {
  return [];
}

let selectedItem = null;

function normalize(link) {
  if (!link) return '';
  return link.split('?')[0].trim().toLowerCase();
}

for (const item of items) {
  const { title, link, message, category } = item.json;
  const cleanLink = normalize(link);

  // Skip if already posted
  if (staticData.db.posted[cleanLink]) {
    continue;
  }

  // 🔒 Activate Lock Immediately
  staticData.db.lock = true;

  // Save as posted
  staticData.db.posted[cleanLink] = {
    title,
    postedAt: new Date().toISOString()
  };

  selectedItem = {
    json: {
      title,
      link,
      message,
      category
    }
  };

  break;
}

// If nothing new → unlock
if (!selectedItem) {
  staticData.db.lock = false;
  return [];
}

return [selectedItem];

const input = $input.first();
const category = $('Duplicate Check').item.json.category;

// Cloudinary fallback images
const fallbackImages = {
  crypto: 'https://res.cloudinary.com/dsqachne0/image/upload/v1770043151/ChatGPT_Image_Feb_2_2026_07_37_38_PM_gpahwu.png',
  gold: 'https://res.cloudinary.com/dsqachne0/image/upload/v1770043646/ChatGPT_Image_Feb_2_2026_07_46_53_PM_jk4xcb.png',
  finance: 'https://res.cloudinary.com/dsqachne0/image/upload/v1770043843/ChatGPT_Image_Feb_2_2026_07_49_56_PM_irsivw.png'
};

let html = '';
let imageUrl = null;

// If fetch failed → data may not exist
if (input && input.json && input.json.data) {
  html = input.json.data;
}

// Try extracting og:image
if (html) {
  let match = html.match(/<meta\s+property=["']og:image["']\s+content=["']([^"']+)["']/i);

  if (!match) {
    match = html.match(/<meta\s+name=["']twitter:image["']\s+content=["']([^"']+)["']/i);
  }

  if (match && match[1].startsWith('http')) {
    imageUrl = match[1];
  }
}

// 🚀 FINAL GUARANTEE
if (!imageUrl) {
  imageUrl = fallbackImages[category] || fallbackImages.finance;
}

return [
  {
    json: {
      imageUrl
    }
  }
];

const staticData = $getWorkflowStaticData('global');

if (staticData.db) {
  staticData.db.lock = false;
}

return $input.all();
